// artworkKindType maps a UI kind (the plain-language switcher label) to the API
// image-type path segment used by /api/v1/artists/{id}/images/{type}/...
func artworkKindType(kind string) string {
	switch kind {
	case "primary":
		return "thumb"
	case "backdrops":
		return "fanart"
	default:
		return kind // logo, banner
	}
}

