// artworkTileAspectClass returns the aspect-ratio utility class for an identity
// tile, keeping each kind aspect-true (Primary 1:1, Logo wide-contain, Banner ~4:1).
func artworkTileAspectClass(kind string) string {
	switch kind {
	case "primary":
		return "aspect-square"
	case "logo":
		return "aspect-[5/2]"
	case "banner":
		return "aspect-[4/1]"
	default:
		return "aspect-square"
	}
}

