// artworkSeverityDotClass maps a severity to its dot background.
func artworkSeverityDotClass(severity string) string {
	switch severity {
	case "error":
		return "bg-red-500"
	case "warning":
		return "bg-amber-500"
	default:
		return "bg-blue-500"
	}
}

