// artworkConnStatus classifies one connection for the reconciliation line.
// Managed => Stillwater owns the folder (gate-exempt). Emby/Jellyfin not
// managed => mirror that may also keep its own internal copy (out-of-folder
// note). Anything else not managed => plain mirror of the shared folder.
func artworkConnStatus(conn templates.ArtistDetailConnection) artworkReconcileStatus {
	if conn.Managed {
		return artworkReconcileStatus{dotClass: "bg-green-500", labelKey: "artist.artwork.recon_managed"}
	}
	if conn.Type == "emby" || conn.Type == "jellyfin" {
		return artworkReconcileStatus{dotClass: "bg-amber-500", labelKey: "artist.artwork.recon_mirror_internal"}
	}
	return artworkReconcileStatus{dotClass: "bg-gray-400", labelKey: "artist.artwork.recon_mirror"}
}

